/*
	kiwa72 추가 내용
	STM32 7시리즈 32bit CRC 1차 결과물
	- CRC 관련 -

	소스: 12345678
	결과: 0xa23ab4d8

	소스: 
	결과: Result: 0x274de10

	※ 위 결과에 대한 검증 필요
*/
#include <stdint.h>
#include "common.h"

#define POLYNOMIAL				0x04C11DB7U
#define INITIAL_REMAINDER		0xFFFFFFFF
//#define FINAL_XOR_VALUE		0xFFFFFFFF
#define FINAL_XOR_VALUE			0x00


#define WIDTH   (8 * sizeof(width))	//-> 32
#define TOPBIT  (1 << (WIDTH - 1))


extern width  crcTable[256];

// CRC 초기화
void crcInit(void);

// CRC-8
width crcCompute(unsigned char* message, unsigned int nBytes);

// CRC-32/MPEG-2
width crcCompute32(unsigned int* message, unsigned int nBytes);

#endif  // DEF_LIBCRC_CHECKSUM_H

